def find_top_selling_product(file_path='Python Sales'):
    top_product = None
    top_revenue = 0.0

    try:
        with open(file_path, newline='', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            for lineno, row in enumerate(reader, start=2):
                product_name = (row.get('product_name') or '').strip()
                price_s = (row.get('price') or '').strip()
                qty_s = (row.get('quantity') or '').strip()
                try:
                    price = float(price_s)
                    qty = int(qty_s)
                except ValueError:
                    print(f"ValueError: invalid numeric value on line {lineno}: price={price_s!r}, quantity={qty_s!r}")
                    return None

                revenue = price * qty
                if product_name and revenue > top_revenue:
                    top_revenue = revenue
                    top_product = product_name
    except FileNotFoundError:
        print(f"FileNotFoundError: CSV file not found: {file_path!r}")
        return None
    except Exception as e:
        print(f"Unexpected error: {e}")
        return None

    if top_product is None:
        print("No valid product data found.")
        return None

    return top_product, top_revenue


